BEHAVIOR_ID='verify-before-done'
BEHAVIOR_NAME='Verify Before Shipping'
DEFAULT_LEVEL='silent'
ESCALATION_JSON='[{"after":1,"level":"nudge"},{"after":2,"level":"warning"},{"after":3,"level":"soft_block"}]'
BLOCK_REASON='[{behavior_id}] BLOCKED: run tests/build before pushing.'
RECOVERY_HINT='Run your test or build command (pytest, npm test, go test, etc.) before pushing. A single test run grants the push.'
NUDGE_TEMPLATE='{behavior_name}: push without prior tests (violation {counter})'
WARNING_TEMPLATE='[{behavior_id}] pushing unverified code — run tests first. counter={counter}'
EVENT_NAME='PreToolUse'

PAYLOAD=$(cat)
SESSION_ID=$(printf '%s' "$PAYLOAD" | forge_session_id)
TOOL_NAME=$(printf '%s' "$PAYLOAD" | jq -r '.tool_name // empty')
# For PreToolUse/PostToolUse, conditions see tool_input.
