        nval = float(val)
    except (TypeError, ValueError):
        return False
    if op == 'gt':     return nv >  nval
    if op == 'lt':     return nv <  nval
    if op == 'gte':    return nv >= nval
    if op == 'lte':    return nv <= nval
    return False

results = [check(c) for c in conditions]
if logic == 'any':
    ok = any(results) if results else True
